const { ethers } = require("hardhat");

const PRECOMPILE_ADDR = "0x0000000000000000000000000000000000000804";
const XCM_MESSAGE_HEX = "";

async function main() {
    console.log("Testing weighMessage() on XCM Precompile...");
    const [deployer] = await ethers.getSigners();

    // Interface
    const iface = new ethers.Interface([
        "function weighMessage(bytes calldata message) external view returns (uint64 refTime, uint64 proofSize)"
    ]);

    const precompile = new ethers.Contract(PRECOMPILE_ADDR, iface, deployer);

    console.log("Calling weighMessage...");
    try {
        const result = await precompile.weighMessage(XCM_MESSAGE_HEX);
        console.log("✅ Custom Weigh Successful!");
        console.log("   RefTime:", result.refTime.toString());
        console.log("   ProofSize:", result.proofSize.toString());
    } catch (e) {
        console.log("❌ Failed to weigh message:", e);
    }
}

main().catch(console.error);
